function Badge({ label, color }: { label: string; color: string }) {
  return (
    <span
      style={{
        display: "inline-block",
        padding: "2px 8px",
        borderRadius: "100px",
        fontSize: "11px",
        fontWeight: 600,
        background: `${color}20`,
        color,
        border: `1px solid ${color}40`,
      }}
    >
      {label}
    </span>
  );
}

const STATUS_COLORS: Record<
  ServiceStatus,
  { bg: string; text: string; label: string }
> = {
  healthy: {
    bg: "color-mix(in srgb, var(--io-success) 12%, transparent)",
    text: "var(--io-success)",
    label: "Ready",
  },
  degraded: {
    bg: "color-mix(in srgb, var(--io-warning) 15%, transparent)",
    text: "var(--io-warning)",
    label: "Degraded",
  },
  unhealthy: {
    bg: "color-mix(in srgb, var(--io-danger) 12%, transparent)",
    text: "var(--io-danger)",
    label: "Not Ready",
  },
  unknown: {
    bg: "var(--io-surface-secondary)",
    text: "var(--io-text-muted)",
    label: "Unknown",
  },
};

function StatusBadge({ status }: { status: ServiceStatus }) {
  const c = STATUS_COLORS[status];
  return (
    <span
      style={{
        display: "inline-flex",
        alignItems: "center",
        gap: "5px",
        fontSize: "12px",
        padding: "3px 10px",
        borderRadius: "100px",
        background: c.bg,
        color: c.text,
        fontWeight: 700,
      }}
    >
      <span
        aria-hidden="true"
        style={{
          width: "6px",
          height: "6px",
          borderRadius: "50%",
          background: c.text,
          flexShrink: 0,
        }}
      />
      {c.label}
    </span>
  );
}

